import { describe, it, expect, vi, beforeEach } from 'vitest'

describe('GET /api/health', () => {
  beforeEach(() => {
    vi.resetModules()
  })

  async function getHandler() {
    const mod = await import('./health')
    const routeOptions = (mod.Route as any).options
    return routeOptions.server.handlers.GET
  }

  it('returns 200 with JSON content type', async () => {
    const handler = await getHandler()
    const response = await handler({ request: new Request('http://localhost/api/health') })

    expect(response).toBeInstanceOf(Response)
    expect(response.status).toBe(200)
    expect(response.headers.get('content-type')).toContain('application/json')
  })

  it('returns status "ok"', async () => {
    const handler = await getHandler()
    const response = await handler({ request: new Request('http://localhost/api/health') })
    const body = await response.json()

    expect(body.status).toBe('ok')
  })

  it('returns a valid ISO 8601 timestamp', async () => {
    const handler = await getHandler()
    const response = await handler({ request: new Request('http://localhost/api/health') })
    const body = await response.json()

    expect(body.timestamp).toBeDefined()
    const parsed = new Date(body.timestamp)
    expect(parsed.toISOString()).toBe(body.timestamp)
  })

  it('returns uptime_seconds as a non-negative integer', async () => {
    const handler = await getHandler()
    const response = await handler({ request: new Request('http://localhost/api/health') })
    const body = await response.json()

    expect(typeof body.uptime_seconds).toBe('number')
    expect(body.uptime_seconds).toBeGreaterThanOrEqual(0)
    expect(Number.isInteger(body.uptime_seconds)).toBe(true)
  })
})

